// Normalize RSS items to {title, link, source, pubDate, summary}
// Input: items from RSS HTTP Request nodes (raw XML in item.json.data or item.json.body)
// Output: flat list of normalized items

const AI_KEYWORDS = /\b(AI|KI|ML|LLM|GPT|Claude|neural|model|machine learning|deep learning|generative|transformer|Anthropic|OpenAI|Gemini|Llama)\b/i;

function stripCdata(s) {
  return s.replace(/<!\[CDATA\[([\s\S]*?)\]\]>/g, '$1');
}

function stripTags(s) {
  return s.replace(/<[^>]+>/g, '').replace(/\s+/g, ' ').trim();
}

function sourceFromUrl(rawUrl) {
  try {
    const u = new URL(rawUrl);
    const host = u.hostname.replace(/^www\./, '');
    const map = {
      'heise.de': 'Heise',
      'rss.golem.de': 'Golem',
      'golem.de': 'Golem',
      'tagesschau.de': 'Tagesschau',
      'sueddeutsche.de': 'Süddeutsche Zeitung',
      'technologyreview.com': 'MIT Tech Review',
      'arstechnica.com': 'Ars Technica',
      'theverge.com': 'The Verge',
      'anthropic.com': 'Anthropic',
      'venturebeat.com': 'VentureBeat',
      'techcrunch.com': 'TechCrunch',
      'wired.com': 'Wired',
      'nature.com': 'Nature',
      'openai.com': 'OpenAI',
      'huggingface.co': 'Hugging Face',
      'zdnet.de': 'ZDNet',
      'derstandard.at': 'Der Standard',
      'science.apa.at': 'APA Wissenschaft'
    };
    return map[host] || host;
  } catch (e) {
    return 'Unknown';
  }
}

const normalized = [];

for (const item of items) {
  const xml = (typeof item.json === 'string') ? item.json
    : (item.json.data || item.json.body || item.json.content || '');

  // Track source from request URL if available
  const requestUrl = item.json.url || item.json.requestUrl || '';
  const fallbackSource = sourceFromUrl(requestUrl);

  // Match <item>...</item> (RSS/RDF) or <entry>...</entry> (Atom)
  const itemRegex = /<(?:item|entry)[\s\S]*?>([\s\S]*?)<\/(?:item|entry)>/g;
  let match;
  while ((match = itemRegex.exec(xml)) !== null) {
    const block = match[1];

    const titleM = block.match(/<title[^>]*>([\s\S]*?)<\/title>/);
    const title = titleM ? stripTags(stripCdata(titleM[1])) : '';

    const linkM = block.match(/<link[^>]*?href="([^"]+)"[^>]*\/?\s*>/) || block.match(/<link[^>]*>([\s\S]*?)<\/link>/);
    const link = linkM ? (linkM[1] || '').trim() : '';

    const pubM = block.match(/<pubDate[^>]*>([\s\S]*?)<\/pubDate>/) || block.match(/<published[^>]*>([\s\S]*?)<\/published>/) || block.match(/<updated[^>]*>([\s\S]*?)<\/updated>/);
    const pubDate = pubM ? pubM[1].trim() : new Date().toISOString();

    const descM = block.match(/<description[^>]*>([\s\S]*?)<\/description>/) || block.match(/<summary[^>]*>([\s\S]*?)<\/summary>/);
    let summary = descM ? stripTags(stripCdata(descM[1])) : '';
    if (summary.length > 300) summary = summary.substring(0, 297) + '...';

    const source = sourceFromUrl(link) === 'Unknown' ? fallbackSource : sourceFromUrl(link);

    // Filter: KI/AI relevance (title or summary must contain a keyword)
    if (title && link && (AI_KEYWORDS.test(title) || AI_KEYWORDS.test(summary))) {
      normalized.push({
        json: {
          title,
          link,
          source,
          pubDate,
          summary,
          origin: 'rss'
        }
      });
    }
  }
}

return normalized;

// Normalize z-ai web search results to same schema as RSS items
// Expected input: item.json.data.results[] (or item.json.results[])

const out = [];

for (const item of items) {
  const results = (item.json && (item.json.data || item.json)).results || (item.json && item.json.data && item.json.data.results) || [];
  for (const r of results) {
    const title = r.title || r.name || '';
    const link = r.url || r.link || '';
    const summary = (r.snippet || r.description || r.content || '').substring(0, 300);
    const pubDate = r.published_at || r.date || new Date().toISOString();
    let source = 'Unknown';
    try {
      const u = new URL(link);
      source = u.hostname.replace(/^www\./, '');
    } catch (e) {}
    if (title && link) {
      out.push({
        json: {
          title,
          link,
          source,
          pubDate,
          summary,
          origin: 'websearch'
        }
      });
    }
  }
}

return out;

// Dedupe items by URL (normalized: strip trailing slash, query params utm_*, fbclid, gclid)
// Also dedupe by title-similarity (lowercase, trim, first 80 chars)

function normalizeUrl(u) {
  try {
    const parsed = new URL(u);
    // Strip tracking params
    ['utm_source', 'utm_medium', 'utm_campaign', 'utm_term', 'utm_content', 'fbclid', 'gclid', 'mc_cid', 'mc_eid'].forEach(p => parsed.searchParams.delete(p));
    let clean = parsed.origin + parsed.pathname;
    if (parsed.search) clean += parsed.search;
    return clean.replace(/\/$/, '').toLowerCase();
  } catch (e) {
    return (u || '').toLowerCase().trim();
  }
}

const seenUrl = new Set();
const seenTitle = new Set();
const deduped = [];

for (const item of items) {
  const url = normalizeUrl(item.json.link);
  const titleKey = (item.json.title || '').toLowerCase().replace(/[^a-z0-9\s]/g, '').trim().substring(0, 80);

  if (seenUrl.has(url) || seenTitle.has(titleKey)) continue;
  seenUrl.add(url);
  seenTitle.add(titleKey);
  deduped.push(item);
}

return deduped;

