// Parse LLM JSON response.
// Input: item.json (chat completion response) with choices[0].message.content
// Output: { date, summaryDe, summaryEn, items[] }

function extractJson(text) {
  if (!text) return null;
  // Try direct parse
  try { return JSON.parse(text); } catch (e) {}
  // Strip code fences
  const fence = text.match(/```(?:json)?\s*([\s\S]*?)```/);
  if (fence) {
    try { return JSON.parse(fence[1]); } catch (e) {}
  }
  // Find first { ... last }
  const start = text.indexOf('{');
  const end = text.lastIndexOf('}');
  if (start >= 0 && end > start) {
    try { return JSON.parse(text.substring(start, end + 1)); } catch (e) {}
  }
  return null;
}

const out = [];
for (const item of items) {
  const content = item.json && item.json.choices && item.json.choices[0] && item.json.choices[0].message && item.json.choices[0].message.content;
  const parsed = extractJson(content);
  if (!parsed) {
    throw new Error('LLM response was not valid JSON. Raw content: ' + (content || '').substring(0, 500));
  }
  // Validate shape
  if (!parsed.summaryDe || !parsed.summaryEn || !Array.isArray(parsed.items)) {
    throw new Error('LLM response missing required fields. Got keys: ' + Object.keys(parsed).join(', '));
  }
  out.push({
    json: {
      date: new Date().toISOString().substring(0, 10),
      summaryDe: parsed.summaryDe,
      summaryEn: parsed.summaryEn,
      items: parsed.items.map((it, idx) => ({
        position: idx + 1,
        headline: it.headline || '',
        descriptionDe: it.descriptionDe || '',
        descriptionEn: it.descriptionEn || '',
        source: it.source || '',
        sourceUrl: it.sourceUrl || ''
      }))
    }
  });
}
return out;

